import{_ as r,c as t,o as l,a1 as e}from"./chunks/framework.DDNAyvCW.js";const o="/assets/general.BZY9l-hs.png",p=JSON.parse('{"title":"通用设置","description":"","frontmatter":{},"headers":[],"relativePath":"docs/settings/general/index.md","filePath":"docs/settings/general/index.md"}'),i={name:"docs/settings/general/index.md"};function n(s,a,h,d,g,u){return l(),t("div",null,a[0]||(a[0]=[e('<h1 id="通用设置" tabindex="-1">通用设置 <a class="header-anchor" href="#通用设置" aria-label="Permalink to &quot;通用设置&quot;">​</a></h1><p>设置页面包含系统的各项通用配置，让您自定义 Chaterm 的外观、布局与编辑器行为。</p><p><img src="'+o+'" alt=""></p><h2 id="通用设置-1" tabindex="-1">通用设置 <a class="header-anchor" href="#通用设置-1" aria-label="Permalink to &quot;通用设置&quot;">​</a></h2><h3 id="主题" tabindex="-1">主题 <a class="header-anchor" href="#主题" aria-label="Permalink to &quot;主题&quot;">​</a></h3><p>选择界面主题：</p><ul><li><strong>暗色主题</strong>：适合在光线较暗的环境中使用，减少眼部疲劳</li><li><strong>亮色主题</strong>：适合在光线充足的环境中使用，提供清晰的视觉效果</li><li><strong>跟随系统</strong>：根据系统设置自动切换主题</li></ul><h3 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h3><p>支持开启自定义背景：</p><ul><li><strong>开启</strong>：可以上传本地背景图片或选择系统背景</li><li><strong>关闭</strong>：使用默认主题背景</li></ul><h3 id="布局" tabindex="-1">布局 <a class="header-anchor" href="#布局" aria-label="Permalink to &quot;布局&quot;">​</a></h3><p>选择界面布局：</p><ul><li><strong>Terminal 布局</strong>：传统终端布局</li><li><strong>Agents 布局</strong>：AI Agent 优先布局</li></ul><h3 id="语言" tabindex="-1">语言 <a class="header-anchor" href="#语言" aria-label="Permalink to &quot;语言&quot;">​</a></h3><p>选择界面语言：</p><ul><li><strong>简体中文</strong></li><li><strong>繁體中文</strong></li><li><strong>English</strong></li><li><strong>Deutsch</strong></li><li><strong>Français</strong></li><li><strong>Italiano</strong></li><li><strong>Português</strong></li><li><strong>Русский</strong></li><li><strong>日本語</strong></li><li><strong>한국어</strong></li></ul><p>切换后立即生效，无需重启应用程序。</p><h3 id="水印" tabindex="-1">水印 <a class="header-anchor" href="#水印" aria-label="Permalink to &quot;水印&quot;">​</a></h3><p>选择开启或关闭界面水印：</p><ul><li><strong>开启</strong>：在界面上显示水印</li><li><strong>关闭</strong>：隐藏界面水印，提供更简洁的界面</li></ul><h2 id="编辑器设置" tabindex="-1">编辑器设置 <a class="header-anchor" href="#编辑器设置" aria-label="Permalink to &quot;编辑器设置&quot;">​</a></h2><p>用于配置应用内代码/文本编辑器的显示与行为。</p><h3 id="字体大小" tabindex="-1">字体大小 <a class="header-anchor" href="#字体大小" aria-label="Permalink to &quot;字体大小&quot;">​</a></h3><p>设置编辑器内文字大小，范围 8～32，单位为像素。</p><h3 id="行高" tabindex="-1">行高 <a class="header-anchor" href="#行高" aria-label="Permalink to &quot;行高&quot;">​</a></h3><p>设置编辑器行高，范围 0～48。为 0 时由编辑器自动计算。</p><h3 id="字体" tabindex="-1">字体 <a class="header-anchor" href="#字体" aria-label="Permalink to &quot;字体&quot;">​</a></h3><p>从预设字体列表中选择编辑器使用的等宽字体（如 Cascadia Mono 等）。</p><h3 id="制表符大小-空格" tabindex="-1">制表符大小（空格） <a class="header-anchor" href="#制表符大小-空格" aria-label="Permalink to &quot;制表符大小（空格）&quot;">​</a></h3><p>设置按 Tab 键插入的空格数量，范围 1～8。</p><h3 id="自动换行" tabindex="-1">自动换行 <a class="header-anchor" href="#自动换行" aria-label="Permalink to &quot;自动换行&quot;">​</a></h3><ul><li><strong>开启</strong>：长行自动换行显示</li><li><strong>关闭</strong>：长行横向滚动显示</li></ul><h3 id="小地图" tabindex="-1">小地图 <a class="header-anchor" href="#小地图" aria-label="Permalink to &quot;小地图&quot;">​</a></h3><ul><li><strong>开启</strong>：在编辑器一侧显示代码小地图</li><li><strong>关闭</strong>：隐藏小地图</li></ul><h3 id="鼠标滚轮缩放" tabindex="-1">鼠标滚轮缩放 <a class="header-anchor" href="#鼠标滚轮缩放" aria-label="Permalink to &quot;鼠标滚轮缩放&quot;">​</a></h3><ul><li><strong>开启</strong>：支持使用 Ctrl + 鼠标滚轮缩放编辑器字体</li><li><strong>关闭</strong>：禁用滚轮缩放</li></ul>',36)]))}const b=r(i,[["render",n]]);export{p as __pageData,b as default};
